static RingBuffer_t rx_ring;
int RingBuffer_Read(uint8_t *out) {
  if (rx_ring.head == rx_ring.tail) return -1; /* 空 */
  *out = rx_ring.buffer[rx_ring.tail];
  rx_ring.tail = (rx_ring.tail + 1) % rx_ring.size;
  return 0;
}
